  useFocusEffect(
    React.useCallback(() => {
      setHasAttemptedRescue(false);
      rescueClear();
      return undefined;
    }, [rescueClear])
  );

  const handleGoBack = () => {
    setHasAttemptedRescue(false);
    rescueClear();
    navigation.goBack();
  };

